using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpHttpServer.Tools;

[McpServerToolType]
public static class ServerTools
{
    [McpServerTool, Description("Echoes a message back with a timestamp.")]
    public static string Echo(
        [Description("The message to echo")] string message)
    {
        return $"[{DateTime.UtcNow:O}] {message}";
    }

    [McpServerTool, Description("Adds two numbers together and returns the sum.")]
    public static string Add(
        [Description("First number")] double a,
        [Description("Second number")] double b)
    {
        return $"{a} + {b} = {a + b}";
    }
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpHttpServer.Resources;

[McpServerResourceType]
public static class ConfigResource
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerResource(
        UriTemplate = "config://app/settings",
        Name = "App Settings",
        MimeType = "application/json"),
     Description("Returns current application configuration as JSON.")]
    public static string GetAppSettings()
    {
        var config = new
        {
            AppName = "McpHttpServer",
            Version = "1.0.0",
            Environment = Environment.GetEnvironmentVariable("ASPNETCORE_ENVIRONMENT") ?? "Production",
            Features = new { EnableCaching = true, MaxRequestsPerMinute = 60 }
        };

        return JsonSerializer.Serialize(config, JsonOptions);
    }

    [McpServerResource(
        UriTemplate = "config://app/status",
        Name = "Server Status",
        MimeType = "application/json"),
     Description("Returns server runtime status information.")]
    public static string GetServerStatus()
    {
        var status = new
        {
            Status = "Healthy",
            Uptime = Environment.TickCount64 / 1000,
            MachineName = Environment.MachineName,
            Timestamp = DateTime.UtcNow
        };

        return JsonSerializer.Serialize(status, JsonOptions);
    }
}

